@login_required
def mark_notification_read(request, pk):
	notification = get_object_or_404(Notification, pk=pk, user=request.user)
	notification.is_read = True
	notification.save(update_fields=['is_read'])
	messages.success(request, 'Notification marked as read.')
	return redirect('notifications')


@login_required
def data_management(request):
	"""Display all subjects with options to edit or delete."""
	subjects = Subject.objects.filter(user=request.user).prefetch_related('grades', 'goals').order_by('name')

	subject_data = []
	for subject in subjects:
		grades = subject.grades.all()
		goals = subject.goals.filter(active=True)

		# Calculate average
		if grades:
			average = sum(float(g.grade) for g in grades) / len(grades)
			average = round(average, 2)
		else:
			average = None

		# Get target grade from active goal
		target_grade = None
		if goals:
			target_grade = goals.first().target_grade

		subject_data.append({
			'subject': subject,
			'grades_count': grades.count(),
			'average': average,
			'target_grade': target_grade,
			'goals_count': goals.count(),
		})

	context = {
		'subject_data': subject_data,
		'total_subjects': len(subjects),
	}
	return render(request, 'data_management.html', context)


@login_required
def edit_subject(request, pk):
	"""Edit subject name."""
	subject = get_object_or_404(Subject, pk=pk, user=request.user)

	if request.method == 'POST':
		new_name = request.POST.get('name', '').strip()
		if new_name:
			# Check if name already exists for this user
			existing = Subject.objects.filter(user=request.user, name__iexact=new_name).exclude(pk=pk).first()
			if existing:
				messages.error(request, f'A subject named "{new_name}" already exists.')
			else:
				subject.name = ' '.join(new_name.split())  # Normalize spacing
				subject.save(update_fields=['name'])
				messages.success(request, f'Subject "{subject.name}" updated successfully.')
				return redirect('data_management')
		else:
			messages.error(request, 'Subject name cannot be empty.')

	context = {'subject': subject}
	return render(request, 'edit_subject.html', context)


@login_required
def delete_subject(request, pk):
	"""Delete subject and all associated data."""
	subject = get_object_or_404(Subject, pk=pk, user=request.user)
	subject_name = subject.name

	if request.method == 'POST':
		# Delete all grades and goals associated with this subject
		subject.grades.all().delete()
		subject.goals.all().delete()
		subject.delete()
		messages.success(request, f'Subject "{subject_name}" and all associated data have been deleted.')
		return redirect('data_management')

	context = {'subject': subject}
	return render(request, 'delete_subject.html', context)

{% load static %}
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>{% block title %}StudyTrack{% endblock %}</title>
    <link rel="icon" type="image/png" href="{% static 'icons/work-in-progress.png' %}">
    <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet">
    <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
    <style>
        :root {
            color-scheme: dark;
        }

        html, body {
            min-height: 100%;
        }

        body {
            background: #0b0b0d;
            color: #f3f4f6;
        }

        a {
            color: #fb923c;
        }

        a:hover {
            color: #fdba74;
        }

        .app-shell {
            min-height: 100vh;
            display: flex;
            background: linear-gradient(180deg, #0b0b0d 0%, #111216 100%);
        }

        .sidebar {
            width: 280px;
            background: #050506;
            border-right: 1px solid rgba(255, 255, 255, 0.08);
            padding: 1.25rem;
            position: sticky;
            top: 0;
            height: 100vh;
            overflow-y: auto;
        }

        .sidebar-brand {
            color: #ffffff;
            font-weight: 800;
            letter-spacing: 0.04em;
            text-decoration: none;
            display: block;
            margin-bottom: 1.25rem;
        }

        .sidebar-brand:hover {
            color: #ffffff;
        }

        .sidebar-section {
            color: #9ca3af;
            text-transform: uppercase;
            font-size: 0.74rem;
            letter-spacing: 0.12em;
            margin: 1.25rem 0 0.5rem;
        }

        .sidebar-nav {
            flex: 1;
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }

        .sidebar-nav a {
            color: #e5e7eb;
            text-decoration: none;
            padding: 0.8rem 0.95rem;
            border-radius: 0.9rem;
            background: rgba(255, 255, 255, 0.03);
            border: 1px solid rgba(255, 255, 255, 0.06);
            transition: all 0.2s ease;
        }

        .sidebar-link-content {
            display: inline-flex;
            align-items: center;
            gap: 0.7rem;
        }

        .sidebar-icon {
            width: 18px;
            height: 18px;
            object-fit: contain;
            filter: invert(58%) sepia(92%) saturate(1600%) hue-rotate(347deg) brightness(101%) contrast(99%);
        }

        .sidebar-nav form {
            margin: 0;
        }

        .sidebar-nav .nav-action {
            width: 100%;
            display: flex;
            align-items: center;
            justify-content: flex-start;
            text-align: left;
            font: inherit;
            color: #e5e7eb;
            padding: 0.8rem 0.95rem;
            border-radius: 0.9rem;
            background: rgba(255, 255, 255, 0.03);
            border: 1px solid rgba(255, 255, 255, 0.06);
            appearance: none;
            -webkit-appearance: none;
            transition: all 0.2s ease;
            cursor: pointer;
        }

        .sidebar-nav .nav-action:hover {
            background: rgba(249, 115, 22, 0.16);
            border-color: rgba(249, 115, 22, 0.28);
            color: #ffffff;
            transform: translateX(2px);
        }

        .sidebar-nav a:hover,
        .sidebar-nav a.active {
            background: rgba(249, 115, 22, 0.16);
            border-color: rgba(249, 115, 22, 0.28);
            color: #ffffff;
            transform: translateX(2px);
        }

        .main-content {
            flex: 1;
            padding: 1.5rem;
        }

        .content-panel {
            max-width: 1200px;
            margin: 0 auto;
        }

        .card,
        .list-group-item,
        .form-control,
        .form-select,
        .modal-content,
        .dropdown-menu {
            background-color: #14151a;
            color: #f3f4f6;
            border-color: rgba(255, 255, 255, 0.08);
        }

        .card {
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.35);
        }

        .table {
            --bs-table-color: #f3f4f6;
            --bs-table-bg: transparent;
            --bs-table-striped-color: #f3f4f6;
            --bs-table-striped-bg: rgba(255, 255, 255, 0.03);
            --bs-table-hover-color: #ffffff;
            --bs-table-hover-bg: rgba(249, 115, 22, 0.08);
            border-color: rgba(255, 255, 255, 0.08);
        }

        .table thead th {
            color: #cbd5e1;
            border-bottom-color: rgba(255, 255, 255, 0.12);
        }

        .form-control::placeholder,
        .form-select::placeholder,
        textarea::placeholder {
            color: #9ca3af;
        }

        .form-control:focus,
        .form-select:focus {
            background-color: #191b21;
            color: #ffffff;
            border-color: #fb923c;
            box-shadow: 0 0 0 0.2rem rgba(249, 115, 22, 0.18);
        }

        .text-muted {
            color: #9ca3af !important;
        }

        .metric-card,
        .soft-shadow {
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.35);
        }

        .bg-primary {
            background-color: #ea580c !important;
        }

        .btn-primary {
            background-color: #f97316;
            border-color: #f97316;
        }

        .btn-outline-primary {
            color: #fb923c;
            border-color: #fb923c;
        }

        .btn-outline-primary:hover {
            background-color: #fb923c;
            border-color: #fb923c;
            color: #050506;
        }

        .alert {
            border: 0;
        }

        .alert-success {
            background: rgba(34, 197, 94, 0.12);
            color: #bbf7d0;
        }

        .alert-danger {
            background: rgba(239, 68, 68, 0.12);
            color: #fecaca;
        }

        .alert-info,
        .alert-primary,
        .alert-warning {
            background: rgba(249, 115, 22, 0.12);
            color: #ffedd5;
        }

        .progress {
            background-color: rgba(255, 255, 255, 0.08);
        }

        .progress-bar {
            background-color: #f97316;
        }

        canvas {
            background: linear-gradient(180deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0.01));
            border-radius: 1rem;
        }

        .brand-mark {
            width: 64px;
            height: 64px;
            border-radius: 14px;
            display: inline-flex;
            align-items: center;
            justify-content: center;
            color: #fff;
            font-weight: 800;
            margin-right: 0.75rem;
        }
        .section-title {
            font-weight: 700;
        }
    </style>
</head>
<body>
<div class="app-shell">
    {% if user.is_authenticated %}
        <aside class="sidebar d-flex flex-column">
            <a class="sidebar-brand" href="{% url 'dashboard' %}">
                <span class="d-flex align-items-center">
                    <img src="{% static 'icons/work-in-progress.png' %}" alt="StudyTrack" class="brand-mark" style="object-fit: contain;">
                    <span>
                        StudyTrack
                        <small class="d-block text-muted fw-normal">Academic Progress Monitor</small>
                    </span>
                </span>
            </a>

            <div class="sidebar-section">Navigation</div>
            <nav class="sidebar-nav">
                <a href="{% url 'dashboard' %}" class="{% if request.resolver_match.url_name == 'dashboard' %}active{% endif %}">
                    <span class="sidebar-link-content">
                        <img class="sidebar-icon" src="https://cdn-icons-png.flaticon.com/512/1995/1995473.png" alt="">
                        <span>Dashboard</span>
                    </span>
                </a>
                <a href="{% url 'add_goal' %}" class="{% if request.resolver_match.url_name == 'add_goal' %}active{% endif %}">
                    <span class="sidebar-link-content">
                        <img class="sidebar-icon" src="https://cdn-icons-png.flaticon.com/512/747/747376.png" alt="">
                        <span>Add Subject and Goal</span>
                    </span>
                </a>
                <a href="{% url 'notifications' %}" class="{% if request.resolver_match.url_name == 'notifications' %}active{% endif %}">
                    <span class="sidebar-link-content">
                        <img class="sidebar-icon" src="https://cdn-icons-png.flaticon.com/512/3239/3239941.png" alt="">
                        <span>Notifications</span>
                    </span>
                </a>
                <a href="{% url 'manage_profile' %}" class="{% if request.resolver_match.url_name == 'manage_profile' %}active{% endif %}">
                    <span class="sidebar-link-content">
                        <img class="sidebar-icon" src="https://cdn-icons-png.flaticon.com/512/1077/1077114.png" alt="">
                        <span>Manage Profile</span>
                    </span>
                </a>
                <form method="post" action="{% url 'logout' %}" class="mt-auto">
                    {% csrf_token %}
                    <button type="submit" class="nav-action w-100">
                        <span class="sidebar-link-content">
                            <img class="sidebar-icon" src="https://cdn-icons-png.flaticon.com/512/2913/2913091.png" alt="">
                            <span>Logout</span>
                        </span>
                    </button>
                </form>
            </nav>
        </aside>
    {% endif %}

    <main class="main-content">
        <div class="content-panel">
            {% if messages %}
                <div class="mb-3">
                    {% for message in messages %}
                        <div class="alert alert-{{ message.tags }} mb-2" role="alert">{{ message }}</div>
                    {% endfor %}
                </div>
            {% endif %}

            {% block content %}{% endblock %}
        </div>
    </main>
</div>

<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js"></script>
{% block scripts %}{% endblock %}
</body>
</html>

